## Integration Patterns

### Pattern 1: Creating and Managing Epochs

```rust
async fn manage_epochs(config: EpochConfig) -> Result<(), Error> {
    let clock = EpochClock::new(config);
    clock.initialize(Time::ZERO);

    // Run operations in current epoch
    let current = clock.current();
    log::info!("Starting operations in {}", current);

    // When ready to transition
    let now = get_current_time();
    let next = clock.advance(now)?;
    log::info!("Advanced to {}", next);

    Ok(())
}
```

### Pattern 2: Symbol Validity Checking

```rust
fn check_symbol_validity(
    symbol: &Symbol,
    window: &SymbolValidityWindow,
    current_epoch: EpochId,
) -> Result<(), EpochError> {
    if !window.contains(current_epoch) {
        return Err(EpochError::ValidityViolation {
            symbol_epoch: current_epoch,
            window: *window,
        });
    }
    Ok(())
}
```

### Pattern 3: Coordinated Epoch Transition

```rust
async fn coordinate_epoch_transition(
    nodes: &[NodeId],
    epoch: EpochId,
    now: Time,
) -> Result<EpochId, Error> {
    let barrier = EpochBarrier::new(epoch, nodes.len() as u32, now)
        .with_timeout(Time::from_secs(30));

    // Notify all nodes
    for node in nodes {
        notify_node(node, epoch).await?;
    }

    // Wait for confirmations
    for node in nodes {
        let confirmation = receive_confirmation(node).await?;
        if let Some(result) = barrier.arrive(&confirmation.node_id, get_current_time())? {
            if result.trigger == BarrierTrigger::AllArrived {
                return Ok(epoch.next());
            }
        }
    }

    Err(Error::new(ErrorKind::ThresholdTimeout)
        .with_context("Not all nodes confirmed epoch transition"))
}
```

### Pattern 4: Grace Period Handling

```rust
fn handle_grace_period(epoch: &Epoch, now: Time) -> EpochState {
    if epoch.state != EpochState::Ending {
        return epoch.state;
    }

    let grace_end = Time::from_nanos(
        epoch.ended_at.unwrap_or(epoch.expected_end).as_nanos()
            + epoch.config.grace_period.as_nanos()
    );

    if now > grace_end {
        EpochState::Ended
    } else {
        EpochState::Ending
    }
}
```

