        assert_eq!(single.span(), 1);
        assert!(single.contains(EpochId(5)));
        assert!(!single.contains(EpochId(4)));

        let infinite = SymbolValidityWindow::infinite();
        assert!(infinite.contains(EpochId::GENESIS));
